solution_code:
#include <iostream>

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;

    int x = 0;
    int y = 0;

    int result = (x = a, y = b);

    std::cout << "x: " << x << '\n';
    std::cout << "y: " << y << '\n';
    std::cout << "result: " << result << '\n';

    return 0;
}

