solution_code:
#include <iostream>

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;

    int x = 0;
    int y = 0;

    // Fixed: (x = a, y = b) returns the right operand's value, which is y = b
    int returned = (x = a, y = b);

    std::cout << "returned: " << returned << '\n';
    return 0;
}
